import React, { useState } from "react";

const CommonTable = ({
  data = [],
  columns = [],
  renderActions,
  noRecordMessage = "No Record Found",
  tableId = "common-table",
  rowsPerPage = 10,
}) => {
  const [currentPage, setCurrentPage] = useState(1);

  const totalPages = Math.ceil(data.length / rowsPerPage);
  const showPagination = data.length > rowsPerPage;

  const startIndex = (currentPage - 1) * rowsPerPage;
  const currentData = data.slice(
    startIndex,
    startIndex + rowsPerPage
  );

  return (
    <div className="table-responsive">
      {data.length === 0 ? (
        <h4 className="text-muted p-5 text-center fw-bold">
          {noRecordMessage}
        </h4>
      ) : (
        <>
          <table
            id={tableId}
            className="table table-striped form-label col-form-label col-form-label-sm"
            role="grid"
          >
            <thead>
              <tr className="align-top">
                {columns.map((col, index) => (
                  <th
                    key={index}
                    style={col.style}
                    className="align-top"
                  >
                    {col.header}
                  </th>
                ))}

                {renderActions && (
                  <th
                    style={{ minWidth: "100px" }}
                    className="align-top"
                  >
                    Action
                  </th>
                )}
              </tr>
            </thead>

            <tbody>
              {currentData.map((row, rowIndex) => (
                <tr
                  key={row.id || row.office_id || rowIndex}
                  className="align-top"
                >
                  {columns.map((col, colIndex) => (
                    <td key={colIndex} className="align-top">
                      {col.render
                        ? col.render(row, rowIndex + startIndex)
                        : row[col.accessor]}
                    </td>
                  ))}

                  {renderActions && (
                    <td className="align-top">
                      <div className="d-flex align-items-center gap-2">
                        {renderActions(row)}
                      </div>
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
          </table>

          {/* Pagination */}
          <div className="d-flex justify-content-between align-items-center mt-3 small">
            <span>
              Showing {startIndex + 1} to{" "}
              {Math.min(startIndex + rowsPerPage, data.length)} of{" "}
              {data.length} records
            </span>

            <ul className="pagination mb-0 small">
              <li
                className={`page-item ${
                  currentPage === 1 ? "disabled" : ""
                }`}
              >
                <button
                  className="page-link"
                  onClick={() =>
                    setCurrentPage((prev) => prev - 1)
                  }
                >
                  Previous
                </button>
              </li>

              {[...Array(totalPages)].map((_, index) => (
                <li
                  key={index}
                  className={`page-item ${
                    currentPage === index + 1 ? "active" : ""
                  }`}
                >
                  <button
                    className="page-link"
                    onClick={() => setCurrentPage(index + 1)}
                  >
                    {index + 1}
                  </button>
                </li>
              ))}

              <li
                className={`page-item ${
                  currentPage === totalPages ? "disabled" : ""
                }`}
              >
                <button
                  className="page-link"
                  onClick={() =>
                    setCurrentPage((prev) => prev + 1)
                  }
                >
                  Next
                </button>
              </li>
            </ul>
          </div>
          // pagination code ends
        </>
      )}
    </div>
  );
};

export default CommonTable;
